import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import API from '../api/axios';

function PostPage() {
  const { id } = useParams();
  const [post, setPost] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // 1. Dito natin ilalagay ang URL ng backend uploads folder mo
  const PF = "http://localhost:5000/uploads/";

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const { data } = await API.get(`/posts/${id}`);
        setPost(data);
      } catch (err) {
        setError('Hindi mahanap ang post na ito. 😅');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  if (loading) return <div className="loading">Loading post... ⏳</div>;
  if (error) return <div className="error-msg">{error}</div>;
  if (!post) return <div>Post not found.</div>;

  return (
    <div className="post-detail-container" style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
      
      {/* 2. Pinagsama natin ang PF (Prefix) at ang filename mula sa database */}
      {post.image && (
        <div style={{ width: '100%', marginBottom: '1.5rem', textAlign: 'center' }}>
          <img 
            src={`${PF}${post.image}`} 
            alt={post.title} 
            style={{ 
              width: '100%', 
              maxHeight: '500px', 
              objectFit: 'cover', 
              borderRadius: '15px',
              boxShadow: '0 4px 12px rgba(0,0,0,0.1)' 
            }}
            // Fallback para sa broken images
            onError={(e) => {
              e.target.onerror = null; 
              e.target.src = "https://via.placeholder.com/800x400?text=Image+Not+Found";
            }}
          />
        </div>
      )}
      
      <h1 style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{post.title}</h1>
      <p className="post-meta" style={{ color: '#666', fontSize: '0.9rem', marginBottom: '1.5rem' }}>
        Published on: {new Date(post.createdAt).toLocaleDateString()}
      </p>
      
      <hr style={{ border: '0', borderTop: '1px solid #eee' }} />
      
      <div className="post-body" style={{ lineHeight: '1.8', fontSize: '1.2rem', marginTop: '2rem', whiteSpace: 'pre-wrap' }}>
        {post.body}
      </div>
      
      <button 
        onClick={() => window.history.back()} 
        style={{ 
          marginTop: '3rem', 
          padding: '12px 25px', 
          cursor: 'pointer',
          backgroundColor: '#333',
          color: '#fff',
          border: 'none',
          borderRadius: '8px',
          fontWeight: 'bold'
        }}
      >
        ⬅️ Back to Home
      </button>
    </div>
  );
}

export default PostPage;
